+func cleanReqPathPreserveTrailingSlash(reqPath string) string {
+	cleaned := path.Clean(reqPath)
+	if strings.HasSuffix(reqPath, "/") && cleaned != "/" {
+		cleaned += "/"
+	}
+
+	return strings.TrimPrefix(cleaned, "/")
